INSERT OR REPLACE INTO crawled_news (id, source, title, link, description, pub_date, region, region_label, categories_json, sort_order) VALUES ('44e3fa111659c2a4', 'Daangn Tech', '모두가 데이터를 다루는 AI 시대, 지난 1년간 데이터 팀은 어떻게 달라졌을까?', 'https://medium.com/daangn/%EB%AA%A8%EB%91%90%EA%B0%80-%EB%8D%B0%EC%9D%B4%ED%84%B0%EB%A5%BC-%EB%8B%A4%EB%A3%A8%EB%8A%94-ai-%EC%8B%9C%EB%8C%80-%EC%A7%80%EB%82%9C-1%EB%85%84%EA%B0%84-%EB%8D%B0%EC%9D%B4%ED%84%B0-%ED%8C%80%EC%9D%80-%EC%96%B4%EB%96%BB%EA%B2%8C-%EB%8B%AC%EB%9D%BC%EC%A1%8C%EC%9D%84%EA%B9%8C-67bdb8fd91d4?source=rss----4505f82a2dbd---4', '', 'Thu, 23 Apr 2026 03:10:32 GMT', 'domestic', '국내', '["AI"]', 244);
